import React from 'react';
import { Link } from 'react-router-dom';

const Cart = () => {
  // Static cart data for now
  const cartItems = [
    { _id: '1', name: 'Signature Trench', price: 850, quantity: 1 },
    { _id: '2', name: 'Cashmere Knit', price: 420, quantity: 1 },
  ];

  const total = cartItems.reduce((acc, item) => acc + item.price * item.quantity, 0);

  return (
    <div className="container">
      <h1 className="page-title">Your Cart</h1>

      {cartItems.length === 0 ? (
        <p style={{ textAlign: 'center' }}>Your cart is empty. <Link to="/shop" style={{ textDecoration: 'underline' }}>Continue shopping.</Link></p>
      ) : (
        <>
          <table className="cart-table">
            <thead>
              <tr>
                <th>Product</th>
                <th>Price</th>
                <th>Quantity</th>
                <th>Total</th>
              </tr>
            </thead>
            <tbody>
              {cartItems.map((item) => (
                <tr key={item._id}>
                  <td>{item.name}</td>
                  <td>${item.price}</td>
                  <td>{item.quantity}</td>
                  <td>${item.price * item.quantity}</td>
                </tr>
              ))}
            </tbody>
          </table>

          <div className="cart-summary">
            <div className="cart-summary-row">
              <span>Subtotal</span>
              <span>${total}</span>
            </div>
            <div className="cart-summary-row">
              <span>Shipping</span>
              <span>Complimentary</span>
            </div>
            <div className="cart-summary-row cart-summary-total">
              <span>Total</span>
              <span>${total}</span>
            </div>
            <button className="btn" style={{ width: '100%', marginTop: '20px' }}>Checkout</button>
          </div>
        </>
      )}
    </div>
  );
};

export default Cart;
